struct MIMEType {
    let type: String
    let subtype: String

    var isWildcard: Bool { type == "*" && subtype == "*" }

    init?(_ string: String) {
        let components: [String] = {
            let stripped = string.trimmingCharacters(in: .whitespacesAndNewlines)
            let split = stripped[..<(stripped.range(of: ";")?.lowerBound ?? stripped.endIndex)]

            return split.components(separatedBy: "/")
        }()

        if components.count == 2, let type = components.first, let subtype = components.last {
            self.type = type
            self.subtype = subtype
        } else {
            return nil
        }
    }

    func matches(_ mime: MIMEType) -> Bool {
        switch (type, subtype) {
        case (mime.type, mime.subtype), (mime.type, "*"), ("*", mime.subtype), ("*", "*"):
            true
        default:
            false
        }
    }
}

func next(_ index: Int) {
    if !hasValue[index] {
        hasValue[index] = true
        numberOfValues += 1
    }

    if numberOfValues == arity {
        do {
            let result = try getResult()
            forwardOn(.next(result))
        } catch let e {
            self.forwardOn(.error(e))
            self.dispose()
        }
    } else {
        var allOthersDone = true

        for i in 0 ..< arity {
            if i != index, !isDone[i] {
                allOthersDone = false
                break
            }
        }

        if allOthersDone {
            forwardOn(.completed)
            dispose()
        }
    }
}

func readUncompressed(
  entry: Entry,
  bufferSize: Int,
  skipCRC32: Bool,
  progress: Progress? = nil,
  with consumer: Consumer
) throws -> CRC32 {
  let size = entry.centralDirectoryStructure.effectiveUncompressedSize
  guard size <= .max else { throw ArchiveError.invalidEntrySize }
  return try Data.consumePart(
    of: Int64(size),
    chunkSize: bufferSize,
    skipCRC32: skipCRC32,
    provider: { _, chunkSize -> Data in
      return try Data.readChunk(of: chunkSize, from: self.archiveFile)
    },
    consumer: { data in
      if progress?.isCancelled == true { throw ArchiveError.cancelledOperation }
      try consumer(data)
      progress?.completedUnitCount += Int64(data.count)
    }
  )
}

func readCompressed(
  entry: Entry,
  bufferSize: Int,
  skipCRC32: Bool,
  progress: Progress? = nil,
  with consumer: Consumer
) throws -> CRC32 {
  let size = entry.centralDirectoryStructure.effectiveCompressedSize
  guard size <= .max else { throw ArchiveError.invalidEntrySize }
  return try Data.decompress(
    size: Int64(size),
    bufferSize: bufferSize,
    skipCRC32: skipCRC32,
    provider: { _, chunkSize -> Data in
      return try Data.readChunk(of: chunkSize, from: self.archiveFile)
    },
    consumer: { data in
      if progress?.isCancelled == true { throw ArchiveError.cancelledOperation }
      try consumer(data)
      progress?.completedUnitCount += Int64(data.count)
    }
  )
}

func writeUncompressed(
  size: Int64,
  bufferSize: Int,
  progress: Progress? = nil,
  provider: Provider
) throws -> (sizeWritten: Int64, checksum: CRC32) {
  var position: Int64 = 0
  var sizeWritten: Int64 = 0
  var checksum = CRC32(0)
  while position < size {
    if progress?.isCancelled == true { throw ArchiveError.cancelledOperation }
    let readSize = (size - position) >= bufferSize ? bufferSize : Int(size - position)
    let entryChunk = try provider(position, readSize)
    checksum = entryChunk.crc32(checksum: checksum)
    sizeWritten += Int64(try Data.write(chunk: entryChunk, to: archiveFile))
    position += Int64(bufferSize)
    progress?.completedUnitCount = sizeWritten
  }
  return (sizeWritten, checksum)
}

func writeCompressed(
  size: Int64,
  bufferSize: Int,
  progress: Progress? = nil,
  provider: Provider
) throws -> (sizeWritten: Int64, checksum: CRC32) {
  var sizeWritten: Int64 = 0
  let consumer: Consumer = { data in sizeWritten += Int64(try Data.write(chunk: data, to: self.archiveFile)) }
  let checksum = try Data.compress(
    size: size,
    bufferSize: bufferSize,
    provider: { position, size -> Data in
      if progress?.isCancelled == true { throw ArchiveError.cancelledOperation }
      let data = try provider(position, size)
      progress?.completedUnitCount += Int64(data.count)
      return data
    },
    consumer: consumer
  )
  return (sizeWritten, checksum)
}

static func consumePart(
  of size: Int64,
  chunkSize: Int,
  skipCRC32: Bool = false,
  provider: Provider,
  consumer: Consumer
) throws -> CRC32 {
  var checksum = CRC32(0)
  guard size > 0 else {
    try consumer(Data())
    return checksum
  }

  let readInOneChunk = (size < chunkSize)
  var chunkSize = readInOneChunk ? Int(size) : chunkSize
  var bytesRead: Int64 = 0
  while bytesRead < size {
    let remainingSize = size - bytesRead
    chunkSize = remainingSize < chunkSize ? Int(remainingSize) : chunkSize
    let data = try provider(bytesRead, chunkSize)
    try consumer(data)
    if !skipCRC32 {
      checksum = data.crc32(checksum: checksum)
    }
    bytesRead += Int64(chunkSize)
  }
  return checksum
}

static func writeLargeChunk(
  _ chunk: Data,
  size: UInt64,
  bufferSize: Int,
  to file: FILEPointer
) throws -> UInt64 {
  var sizeWritten: UInt64 = 0
  chunk.withUnsafeBytes { rawBufferPointer in
    if let baseAddress = rawBufferPointer.baseAddress, rawBufferPointer.count > 0 {
      let pointer = baseAddress.assumingMemoryBound(to: UInt8.self)

      while sizeWritten < size {
        let remainingSize = size - sizeWritten
        let chunkSize = Swift.min(Int(remainingSize), bufferSize)
        let curPointer = pointer.advanced(by: Int(sizeWritten))
        fwrite(curPointer, 1, chunkSize, file)
        sizeWritten += UInt64(chunkSize)
      }
    }
  }
  let error = ferror(file)
  if error > 0 {
    throw DataError.unwritableFile
  }
  return sizeWritten
}

static func scanForZIP64Field(in data: Data, fields: [Field]) -> Entry.ZIP64ExtendedInformation? {
  guard data.isEmpty == false else { return nil }
  var offset = 0
  var headerID: UInt16
  var dataSize: UInt16
  let extraFieldLength = data.count
  let headerSize = Int(Entry.ZIP64ExtendedInformation.headerSize)
  while offset < extraFieldLength - headerSize {
    headerID = data.scanValue(start: offset)
    dataSize = data.scanValue(start: offset + 2)
    let nextOffset = offset + headerSize + Int(dataSize)
    guard nextOffset <= extraFieldLength else { return nil }
    if headerID == ExtraFieldHeaderID.zip64ExtendedInformation.rawValue {
      return Entry.ZIP64ExtendedInformation(data: data.subdata(in: offset..<nextOffset), fields: fields)
    }
    offset = nextOffset
  }
  return nil
}

func cubicBezierInterpolate(_ P0: CGPoint, _ P1: CGPoint, _ P2: CGPoint, _ P3: CGPoint) -> CGFloat {
  var t: CGFloat
  if self == P0.x {
    // Handle corner cases explicitly to prevent rounding errors
    t = 0
  } else if self == P3.x {
    t = 1
  } else {
    // Calculate t
    let a = -P0.x + 3 * P1.x - 3 * P2.x + P3.x
    let b = 3 * P0.x - 6 * P1.x + 3 * P2.x
    let c = -3 * P0.x + 3 * P1.x
    let d = P0.x - self
    let tTemp = CGFloat.SolveCubic(a, b, c, d)
    if tTemp == -1 {
      return -1
    }
    t = tTemp
  }

  // Calculate y from t
  return (1 - t).cubed * P0.y + 3 * t * (1 - t).squared * P1.y + 3 * t.squared * (1 - t) * P2.y + t.cubed * P3.y
}

func hexColorComponents() -> (red: CGFloat, green: CGFloat, blue: CGFloat) {
  var cString: String = trimmingCharacters(in: .whitespacesAndNewlines).uppercased()

  if cString.hasPrefix("#") {
    cString.remove(at: cString.startIndex)
  }

  if (cString.count) != 6 {
    return (red: 0, green: 0, blue: 0)
  }

  var rgbValue: UInt64 = 0
  Scanner(string: cString).scanHexInt64(&rgbValue)

  return (
    red: CGFloat((rgbValue & 0xFF0000) >> 16) / 255.0,
    green: CGFloat((rgbValue & 0x00FF00) >> 8) / 255.0,
    blue: CGFloat(rgbValue & 0x0000FF) / 255.0
  )
}

public func interpolate(
  to: LottieVector3D,
  amount: CGFloat,
  spatialOutTangent: CGPoint?,
  spatialInTangent: CGPoint?
) -> LottieVector3D {
  if spatialInTangent != nil || spatialOutTangent != nil {
    // TODO Support third dimension spatial interpolation
    let point = pointValue.interpolate(
      to: to.pointValue,
      amount: amount,
      spatialOutTangent: spatialOutTangent,
      spatialInTangent: spatialInTangent
    )

    return LottieVector3D(
      x: point.x,
      y: point.y,
      z: CGFloat(z.interpolate(to: to.z, amount: amount))
    )
  }

  return LottieVector3D(
    x: x.interpolate(to: to.x, amount: amount),
    y: y.interpolate(to: to.y, amount: amount),
    z: z.interpolate(to: to.z, amount: amount)
  )
}

private func timingFunctions<KeyframeValue>(
  for keyframes: [Keyframe<KeyframeValue>]
) -> [CAMediaTimingFunction] {
  // Compute the timing function between each keyframe and the subsequent keyframe
  var timingFunctions = [CAMediaTimingFunction]()

  for (index, keyframe) in keyframes.enumerated()
    where index != keyframes.indices.last
  {
    let nextKeyframe = keyframes[index + 1]

    let controlPoint1 = keyframe.outTangent?.pointValue ?? .zero
    let controlPoint2 = nextKeyframe.inTangent?.pointValue ?? CGPoint(x: 1, y: 1)

    timingFunctions.append(CAMediaTimingFunction(
      controlPoints:
      Float(controlPoint1.x),
      Float(controlPoint1.y),
      Float(controlPoint2.x),
      Float(controlPoint2.y)
    ))
  }

  return timingFunctions
}

