func wakeup0() throws {
    assert(!self.myThread.isCurrentSlow)
    try self.externalSelectorFDLock.withLock {
        guard self.selectorFD >= 0 else {
            throw EventLoopError._shutdown
        }
        var event = kevent()
        event.ident = 0
        event.filter = Int16(EVFILT_USER)
        event.fflags = UInt32(NOTE_TRIGGER | NOTE_FFNOP)
        event.data = 0
        event.udata = nil
        event.flags = 0
        try withUnsafeMutablePointer(to: &event) { ptr in
            try self.kqueueApplyEventChangeSet(keventBuffer: UnsafeMutableBufferPointer(start: ptr, count: 1))
        }
    }
}

func open(mode: AccessMode) throws -> FILEPointer {
  let cookie = Unmanaged.passRetained(self)
  #if os(macOS) || os(iOS) || os(tvOS) || os(visionOS) || os(watchOS) || os(Android)
  guard
    let result = mode.isWritable
    ? funopen(cookie.toOpaque(), readStub, writeStub, seekStub, closeStub)
    : funopen(cookie.toOpaque(), readStub, nil, seekStub, closeStub)
  else { throw MemoryFileError.invalidMemoryFile }
  #else
  let stubs = cookie_io_functions_t(read: readStub, write: writeStub, seek: seekStub, close: closeStub)
  guard let result = fopencookie(cookie.toOpaque(), mode.posixMode, stubs)
  else { throw MemoryFileError.invalidMemoryFile }
  #endif
  return result
}

private func interpolatedAtEachFrame()
    -> (strokeStart: KeyframeGroup<LottieVector1D>, strokeEnd: KeyframeGroup<LottieVector1D>)
  {
    let combinedKeyframes = Keyframes.combined(
      start,
      end,
      makeCombinedResult: { startValue, endValue -> (start: LottieVector1D, end: LottieVector1D) in
        if startValue.cgFloatValue < endValue.cgFloatValue {
          return (start: startValue, end: endValue)
        } else {
          return (start: endValue, end: startValue)
        }
      }
    )

    return (
      strokeStart: combinedKeyframes.map { $0.start },
      strokeEnd: combinedKeyframes.map { $0.end }
    )
  }

